// ─────────────────────────────────────────────
// NODE 04 | Code – Parse XML + Extract Last 24h Entries
// FIX: Removed $('02 | Code...') reference — node 02 may not be
//      executed when testing node 04 in isolation.
//      Source is passed through automatically by the HTTP Request
//      node from its input item, so it lives directly on $json.source
// ─────────────────────────────────────────────

// Step 1: Read source directly from current item's json
// The HTTP Request node forwards all input fields to its output
const source = $json.source || 'unknown_source';

// Step 2: Get raw XML — HTTP Request v4 puts response body under $json.data
const rawXml = $json.data || '';

if (!rawXml || rawXml.trim().length === 0) {
  return [{ json: { skip: 'true', source } }];
}

// Step 3: Extract content between XML tags (handles CDATA too)
function extractTag(xml, tag) {
  const patterns = [
    new RegExp(`<${tag}[^>]*><!\\[CDATA\\[([\\s\\S]*?)\\]\\]><\\/${tag}>`, 'i'),
    new RegExp(`<${tag}[^>]*>([\\s\\S]*?)<\\/${tag}>`, 'i')
  ];
  for (const p of patterns) {
    const m = xml.match(p);
    if (m) return m[1].trim();
  }
  return '';
}

// Step 4: Extract href attribute (for Atom <link href="..."/>)
function extractHref(xmlChunk) {
  const m = xmlChunk.match(/href=["']([^"']+)["']/);
  return m ? m[1] : '';
}

// Step 5: Decode HTML entities and strip all HTML tags
function cleanText(text) {
  return text
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&amp;/g, '&')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&apos;/g, "'")
    .replace(/&nbsp;/g, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s{2,}/g, ' ')
    .trim();
}

// Step 6: Split XML into individual entry/item blocks
let blocks = [];
if (rawXml.includes('<entry')) {
  // Atom format
  blocks = rawXml
    .split('<entry')
    .slice(1)
    .map(b => '<entry' + b.split('</entry>')[0] + '</entry>');
} else if (/<item[\s>]/.test(rawXml)) {
  // RSS 2.0 format
  blocks = rawXml
    .split(/<item[\s>]/)
    .slice(1)
    .map(b => '<item>' + b.split('</item>')[0] + '</item>');
}

if (blocks.length === 0) {
  return [{ json: { skip: 'true', source } }];
}

// Step 7: 24h cutoff timestamp
const cutoff = new Date();
cutoff.setHours(cutoff.getHours() - 24);

// Step 8: Parse each block and filter to last 24h only
const items = [];

for (const block of blocks) {
  const title = cleanText(extractTag(block, 'title')) || 'No title';

  // Link extraction: Atom uses href attr, RSS uses tag text or guid
  const linkTagMatch = block.match(/<link[^>]*\/?>/i);
  const linkTag = linkTagMatch ? linkTagMatch[0] : '';
  const link =
    extractHref(linkTag) ||
    cleanText(extractTag(block, 'link')) ||
    cleanText(extractTag(block, 'guid')) ||
    '';

  // Summary: try several common tag names
  const rawSummary =
    extractTag(block, 'summary') ||
    extractTag(block, 'description') ||
    extractTag(block, 'content') ||
    '';
  const summary = cleanText(rawSummary).substring(0, 800);

  // Published date: try several common tag names
  const publishedRaw =
    extractTag(block, 'published') ||
    extractTag(block, 'updated') ||
    extractTag(block, 'pubDate') ||
    new Date().toISOString();

  const pubDate = new Date(publishedRaw);

  if (!isNaN(pubDate.getTime()) && pubDate >= cutoff) {
    items.push({
      json: { source, title, link, summary, published: publishedRaw }
    });
  }
}

// Step 9: Return parsed items or skip sentinel
return items.length > 0
  ? items
  : [{ json: { skip: 'true', source } }];

// FIX: Changed from 'functionCode' to 'jsCode'
// FIX: Node reference uses .first().json (not .item.json which is invalid)
// FIX: OpenAI response in n8n-nodes-langchain is under $json.message.content

const raw = $json.message?.content ||
            $json.choices?.[0]?.message?.content ||
            '{}';

let ai;
try {
  // Strip any accidental markdown code fences the model may add
  const cleaned = raw.replace(/```json\n?|```\n?/g, '').trim();
  ai = JSON.parse(cleaned);
} catch (e) {
  ai = {
    is_opportunity: false,
    intent: 'irrelevant',
    relevance_score: 0,
    pain_point: null,
    opportunity_summary: 'JSON parse error: ' + e.message,
    suggested_action: 'ignore'
  };
}

// FIX: Use $('node name').first().json instead of .item.json
const prev = $('05 | Filter – Skip Empty Feed Results').first().json;

return [{
  json: {
    source: prev.source,
    title: prev.title,
    link: prev.link,
    summary: prev.summary,
    published: prev.published,
    is_opportunity: ai.is_opportunity ?? false,
    intent: ai.intent ?? 'irrelevant',
    relevance_score: Number(ai.relevance_score) || 0,
    pain_point: ai.pain_point ?? null,
    opportunity_summary: ai.opportunity_summary ?? '',
    suggested_action: ai.suggested_action ?? 'ignore',
    analyzed_at: new Date().toISOString()
  }
}];

