// FIX: Changed from 'functionCode' to 'jsCode'
// FIX: This node now receives a SINGLE aggregated item from node 12 (Aggregate node)
//      containing all opportunities in $json.opportunities array.
//      Previously it received items one by one, which made per-source grouping impossible.

const all = $json.opportunities || [];

if (all.length === 0) {
  return [{ json: { digest: 'No opportunities found today.', total: 0, date: new Date().toISOString().split('T')[0] } }];
}

const bySource = {};
for (const post of all) {
  const s = post.source || 'unknown';
  if (!bySource[s]) bySource[s] = [];
  bySource[s].push(post);
}

const dateStr = new Date().toISOString().split('T')[0];
let digest = `*Daily Social Listening Digest – ${dateStr}*\n\n`;

for (const [source, posts] of Object.entries(bySource)) {
  digest += `*${source.toUpperCase()}* (${posts.length} opportunities)\n`;
  for (const p of posts.slice(0, 5)) {
    digest += `  • [Score ${p.relevance_score}] ${p.title}\n    ${p.link}\n`;
  }
  digest += '\n';
}

return [{ json: { digest, total: all.length, date: dateStr } }];
